describe("MockDirectorProvider", () => {
  it("returns a deterministic fixture-backed manifest with usage", async () => {
    const provider = new MockDirectorProvider({
      tokens: { inputTokens: 12, outputTokens: 34, totalTokens: 46 },
      latencyMs: 7,
