  );
  const elapsedMs = Math.max(0, clock.now() - startedAt);

  return {
    gate: 2,
    depth: manifest.depth,
    band: manifest.band,
    candidate: {
      seed: manifest.params.seed,
      stairsReachable: candidate.pathToStairs !== null,
