class FakeStream {
  private readonly listeners: Array<(chunk: string) => void> = [];

  setEncoding(): void {}

  on(event: "data", listener: (chunk: string) => void): void {
    if (event === "data") {
      this.listeners.push(listener);
    }
  }

  emit(chunk: string): void {
    for (const listener of this.listeners) {
      listener(chunk);
    }
  }
}

